var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"또 고철 수집이군. 저번처럼 침식현상은 나타나지 않는 건가?","JPN":"また古鉄集めか。この前みたいに侵食現象が起きたりはしないのかな。","ENG":"Collecting scraps again? Do you think there will be another Counterside Effect like last time?","TWN":"又是收集廢鐵啊，這次不會像上次那樣出現侵蝕體吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"2종한테 다리가 뜯겨나갔던 녀석이 뭔 소리를 하는 거냐.","JPN":"第2種に足を千切られたやつが何を言っている。","ENG":"Is that what a guy who got his leg torn off by a Category 2 should be saying?","TWN":"被區區2類侵蝕體咬掉腿的傢伙在胡說些什麼呢。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"팔다리가 뭐 하루 이틀 날라가는 것도 아니고…","JPN":"まあ手足がぶっ飛ぶのはいつものことだろう。","ENG":"We've been doing this long enough to get a limb torn off here and there...","TWN":"嘿嘿，缺條胳臂少條腿也不是什麼一天兩天事了……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"모두들 오늘도 열심히 해요!","JPN":"皆さん、今日も頑張りましょう！","ENG":"Let's work hard today, everyone!","TWN":"大家！今天也要加油喔！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L10_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"마브카. 오늘은 민병단 분들과 함께 고물 수집을 하는 날이야.","JPN":"マブカ、今日は民兵団の皆さんと古鉄集めに行くの。","ENG":"Mavka, we collect junk with the militia today.","TWN":"瑪卡，今天是我們和民兵團一起收集破銅爛鐵的日子。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"쓸만해 보이는 물건이라면 전부 가져와 줘.","JPN":"使えそうなものならとりあえず全部持って来て。","ENG":"Bring back anything that seems useful.","TWN":"我們要把看起來有用的東西都帶回來。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"응… 알았어.","JPN":"うん、わかった。","ENG":"Okay.","TWN":"嗯……知道了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"그리고 반드시 내 시야 안에서만 활동해야 해. 알았지?","JPN":"あと、必ず私の目が届く範囲内で動いてね。","ENG":"But you have to stay within my sight, okay?","TWN":"而且一定要在我的視線範圍內活動，知道嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"내가 못 보는 곳에서 또 고장나버리면 큰일이잖아.","JPN":"私の知らないところでまた動けなくなったら大変でしょう？","ENG":"Because it'll be a huge problem if you break down when I'm not there.","TWN":"如果在我看不到的地方又壞掉了，那可就糟了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"어쩔 수 없지.","JPN":"仕方ないね。","ENG":"I can't complain about that.","TWN":"真是沒辦法。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"그럼 이 주변만 돌아다닐게.","JPN":"じゃあこの辺で活動するよ。","ENG":"Then, I'll be patrolling around here.","TWN":"那我就在這附近轉轉吧。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"응응! 열심히 해줘~","JPN":"うんうん！　じゃあよろしくね！","ENG":"Okay! Then, see you later!","TWN":"嗯嗯！加油喔～"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"사람이 살았던 흔적이 그대로 있어.","JPN":"人が暮らしていた痕跡が残っている。","ENG":"There are still traces of the people who used to live here.","TWN":"這裡還留有人生活的痕跡。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_WOOD"},{"id":"L21_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"내가 현역 시절부터 있었더라면….","JPN":"現役時代にここに来ていれば……","ENG":"If only I were here when I was still a part of the army...","TWN":"如果我在還沒被廢棄時就來的話……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"걱정할 것 없어. 이런 유배지로 발령받을 일은 없었을 테니까.","JPN":"そもそもこういう流刑地に派遣されることなんてなかったでしょう。","ENG":"No need to worry about that. Because then, you wouldn't be dispatched to a place of exile like here.","TWN":"不用擔心。不會被派到這種邊疆地帶的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_SNOW"},{"id":"L25_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"어제 안드레이를 만났다면서? 내 목소린 기억하고 있지?","JPN":"昨日アンドレイに会ったんだって？　私の声覚えてる？","ENG":"I heard you met with Andrei yesterday. You remember my voice, don't you?","TWN":"聽說你昨天見到安德烈了？還記得我的聲音嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"분명 민병단의 올가… 올가 언니라고 불러야 될까?","JPN":"民兵団のオルガ……　オルガさん、と呼べばいい？","ENG":"You're Olga from the militia... Or would you prefer if I called you Ms. Olga?","TWN":"你是民兵團的歐嘉……該叫你歐嘉姊姊嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"……그냥 올가라고 불러.","JPN":"……オルガでいいよ。","ENG":"...Just Olga is fine.","TWN":"……就叫歐嘉吧。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"그때는 정신이 없어서 제대로 이야기도 못 나눴네.","JPN":"あの時はバタバタしてて、ちゃんとお話もできなかったわね。","ENG":"I don't believe we had a chance to talk that day because of everything going on.","TWN":"那時候情況緊急，沒能好好聊聊。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"우리 마을이 텃세가 심하다는 건 많이 들었겠지?","JPN":"うちの村人たちは警戒心が強いって、聞いてるでしょう？","ENG":"I'm sure you already heard how territorial our village is, right?","TWN":"你應該也發現了，我們村子排外很嚴重吧？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"난 사람들과 원만히 지내고 싶어.","JPN":"私は他の人たちと穏便に過ごしたい。","ENG":"I want to get along with these people.","TWN":"我想和大家和睦相處。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"당연히 그렇겠지.","JPN":"誰でもそう思うでしょうね。","ENG":"Of course, you do.","TWN":"那是當然。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"한번 말해봐.","JPN":"感想を聞かせてもらえるかしら。","ENG":"Then, tell me.","TWN":"說說看吧。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"……이 장소를 와본 소감이 어때?","JPN":"……ここを見て、どう思った？","ENG":"...What is your impression of this place?","TWN":"……來了這裡以後感想如何？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"……처참해.","JPN":"……凄惨だな、と。","ENG":"...It's devastating.","TWN":"……慘不忍睹。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"그뿐이야?","JPN":"それだけ？","ENG":"Is that all?","TWN":"就這樣嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"이곳에 살았던 사람들. 모두 딱하다고 생각하고 있어.","JPN":"ここで暮らしていた人、皆気の毒だと思ってる。","ENG":"I feel bad for everyone who lived here.","TWN":"住在這裡的人。我為他們感到可憐。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"여긴 나와 안드레이가 함께 살았던 곳이야.","JPN":"ここは私とアンドレイが住んでいた場所よ。","ENG":"This place is where Andrei and I grew up.","TWN":"這裡是我和安德烈一起生活的地方。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"카운터 능력은 없었지만, 어떻게든 침식에 대비하며 살아왔지.","JPN":"私たちはカウンターの能力こそなかったものの、なんとか侵食に備えて生活していた。","ENG":"Even though we aren't Counters, we somehow managed to survive against the Corruption.","TWN":"雖然沒有制裁者能力，但我們還是拼命對付侵蝕生存了下來。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"3종 침식체. 우린 <color=#ffd34c>키키모라</color>라고 부르고 있어.","JPN":"第3種侵食体……私たちは<color=#ffd34c>キキーモラ</color>と呼んでいるけど。","ENG":"The Category 3 C.O. We call it <color=#ffd34c>Kikimora</color>.","TWN":"3類侵蝕體。我們叫它<color=#ffd34c>奇奇莫拉</color>。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"그 자식은 땅속이나 하늘에서 튀어나온 것도 아니었어.","JPN":"あいつは地面から生えてきたわけでも、空から降ってきたわけでもない。","ENG":"That thing didn't appear out of the sky or from the ground.","TWN":"那傢伙既不是從地下冒出來的，也不是從天上掉下來的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"그저 갑자기 나타나선… 닥치는대로 다 죽여버렸지.","JPN":"ただ忽然と現れて……目に見えるすべてを殺し尽くした。","ENG":"It just suddenly appeared, and... killed everything in its path.","TWN":"它就是突然出現……然後見人就殺。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"마치 자연재해가 덮친 것 같았어.","JPN":"あれはもはや自然災害だったわ。","ENG":"It was as if a natural disaster had struck.","TWN":"就像突然發生的自然災害一樣。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"침식재난에 논리같은건 통하지 않는다고 하잖아?","JPN":"侵食災害に理屈はないって言うでしょう？","ENG":"You know how they say logic doesn't apply to Corruption disasters, right?","TWN":"雖然他們說侵蝕災難無法用邏輯解釋。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"하지만 난 분명 북방군들의 소행이라 생각하는데.","JPN":"でも私は間違いなく北方軍の仕業だと思ってるの。","ENG":"But I believe that it was what the Northern Army did.","TWN":"但我相信這是北方軍的所作所為。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"……나도 아는 게 그리 많진 않아.","JPN":"……私も詳しいことはわからない。","ENG":"...I don't know much about it either.","TWN":"……我知道的也不多。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"믿어줄진 모르겠지만… 정말이야.","JPN":"信じてもらえないかもしれないけど……本当だよ。","ENG":"I don't know if you trust me, but... it's the truth.","TWN":"你可能不信……但這是真的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"듣고 싶은 말이 아니라서 미안해.","JPN":"聞きたかった答えじゃなくてごめん。","ENG":"I'm sorry for not saying what you wanted to hear.","TWN":"抱歉，我沒有你想聽的話。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"하… 그렇겠지. 그놈들이 너 같은 꼬맹이한테 뭘 알려줬겠어.","JPN":"はあ……でしょうね。あなたみたいな子供に、やつらがそこまで話してるわけないものね。","ENG":"*Sigh* Of course. There's no way those bastards would say anything to a kid like you.","TWN":"呼……也是。那些傢伙怎麼可能什麼都告訴你這種小孩子呢。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"애한테 심문하는 나도 제정신이 아닌 것 같네.","JPN":"子供に尋問じみたことしている私もどうかしているわ。","ENG":"And I'm interrogating a kid... I must be losing it as well.","TWN":"劈頭就審問一個孩子……我也真是瘋了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"쓸만한 물건은 좀 찾았어?","JPN":"使えそうなものは見つかったの？","ENG":"Have you found anything useful?","TWN":"你找到什麼有用的東西了嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"안 그래도 그것 때문에 조금 곤란해.","JPN":"ちょうど今その件で困ってる。","ENG":"I actually wanted to ask about that.","TWN":"我正好因為這個問題有點困擾。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"이것 봐. 이게 뭐였는지 알겠어?","JPN":"ほら、これが何かわかる？","ENG":"Look. Can you tell what this is?","TWN":"那麼……你看，這個你知道是什麼嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L12_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"음… 잘 모르겠어.","JPN":"ん……よくわからない。","ENG":"Mm... I'm not sure.","TWN":"嗯……不知道。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"바로 그거야.","JPN":"それよ。","ENG":"Exactly.","TWN":"就是這樣。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"딱 봤을 때 뭔지 모르는 것만 제외하면, 대부분 쓸만한 물건이야.","JPN":"パッと見て何なのかわからないもの以外は、全部「使えそうなもの」なの。","ENG":"Everything except the things that you can't tell what they are at first glance is salvageable.","TWN":"除了看不出是什麼的東西，大部分都是有用的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"시계, 라디에이터, 만화책… 이건 많이 찢어져 있군.","JPN":"時計、ラジエーター、マンガ……これは結構破れてるわね。","ENG":"A clock, a radiator, a comic book... But this one's very torn.","TWN":"手錶、散熱器、漫畫書……這本破得蠻厲害。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"만화 좋아해?","JPN":"マンガは好き？","ENG":"Do you like comics?","TWN":"你喜歡漫畫嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"브레멘 동물전대는 재밌었던 것 같아.","JPN":"ブレーメン動物戦隊はけっこう面白かったかも。","ENG":"I like Town Soldiers of Bremen.","TWN":"布萊梅動物戰隊好像蠻有趣的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"풉, 소년병도 결국엔 애라는 거네.","JPN":"ぷふっ、少年兵も所詮は子供なのね。","ENG":"Pfft. So even a child soldier is still a kid, eh?","TWN":"噗，你終究還是個孩子。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"그럼 이거 받아. 방금 주운 건데, 사샤라면 분명 고칠 수 있을거야.","JPN":"じゃあ、これ持って行って。さっき拾ったけど、サシャなら直せるはずよ。","ENG":"Then take this. I just found it, and I'm certain Sasha will be able to fix it.","TWN":"那就拿著這個吧。剛撿到的，莎夏一定能修好它。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"이렇게나 많이 들고 갈 수 있을까?","JPN":"こんなにたくさん持ち帰れるかな。","ENG":"Do you think I can bring back this much?","TWN":"這麼多東西，都要帶走嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"사실 여긴 나와 안드레이가 살았던 집이야.","JPN":"実はここ、私とアンドレイが住んでいた家なの。","ENG":"This used to be the house that Andrei and I used to live in.","TWN":"這裡其實是我和安德烈住過的家。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"그 비디오도 태어날 아기를 위한 물건이었지.","JPN":"そのビデオも、もうすぐ生まれてくるはずの子供のためのものだった。","ENG":"That videotape was meant for the baby about to be born.","TWN":"那些錄影帶也是為即將出生的孩子所準備的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"우린 더 이상 필요 없어.","JPN":"でももう要らない。","ENG":"But we don't need it anymore.","TWN":"但現在已經不需要了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"고마워… 올가 언니.","JPN":"ありがとう……オルガさん。","ENG":"Thank you... Ms. Olga.","TWN":"謝謝你……歐嘉姊姊。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"나중에 꼭 챙겨볼게.","JPN":"後でちゃんと見るね。","ENG":"I'll make sure to watch it later.","TWN":"我以後一定會看的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"그러니까 언니라고 부르지 말라니까…","JPN":"だからさん付けは要らないって……","ENG":"Like I said, drop the Ms. and just call me Olga.","TWN":"就說不要叫我姊姊……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"침식경보!","JPN":"侵食警報……！","ENG":"Corruption alert!","TWN":"侵蝕警報！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"서둘러. 민병단과 합류해야 해!","JPN":"急いで、早く民兵団と合流しないと！","ENG":"Hurry. We must regroup with the militia!","TWN":"抓緊時間。得趕快和民兵團會合！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};